import{_ as s,c as e,o as p,ag as t}from"./chunks/framework.Ac_4huKD.js";const i="/block-server-wiki/assets/unfinished_shop.ul5KGfm3.jpg",o="/block-server-wiki/assets/shop.D1gs9Bxd.webp",l="/block-server-wiki/assets/shop_with_items.dZjBZiC3.webp",c="/block-server-wiki/assets/shop_buy_0.BLGKhgeH.jpg",r="/block-server-wiki/assets/shop_buy_1.CjkCQyml.jpg",n="/block-server-wiki/assets/shop_control_panel.BS-CicrG.jpg",v=JSON.parse('{"title":"箱子商店","description":"","frontmatter":{},"headers":[],"relativePath":"zh/quickshop/index.md","filePath":"zh/quickshop/index.md","lastUpdated":1730509339000}'),d={name:"zh/quickshop/index.md"};function h(_,a,m,u,b,k){return p(),e("div",null,a[0]||(a[0]=[t('<h1 id="箱子商店" tabindex="-1">箱子商店 <a class="header-anchor" href="#箱子商店" aria-label="Permalink to &quot;箱子商店&quot;">​</a></h1><h2 id="创建商店" tabindex="-1">创建商店 <a class="header-anchor" href="#创建商店" aria-label="Permalink to &quot;创建商店&quot;">​</a></h2><p>将你的准星对准一个空箱子，手上放着你要出售/收购的东西（这里以钻石镐为例）</p><p>接下来，左键点击箱子，按照聊天框中的提示直接输入要出售/收购的价格</p><p><img src="'+i+'" alt="一个未完成的箱子商店"></p><p>如果一切正确，那么你会看到箱子上多了个牌子：</p><p><img src="'+o+'" alt="一个常见的箱子商店"></p><p>那么恭喜，你已经创建了一个箱子商店！</p><h2 id="为商店补货" tabindex="-1">为商店补货 <a class="header-anchor" href="#为商店补货" aria-label="Permalink to &quot;为商店补货&quot;">​</a></h2><p>一般来说，如果一个商店的物品卖完，箱子前的牌子会显示<code>缺货</code>，且名字会变红（同上图）</p><p>这时候，你需要准备好你要卖的物品，然后将其放入箱子中，即可完成补货。此时箱子会变绿，也会显示可用的物品数量：</p><p><img src="'+l+'" alt="一个可用的商店"></p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>你不能在商店中放置与出售物品不符的东西</p><p>即使都是钻石镐，只要他们的属性不同，那就是不可售卖的</p></div><h2 id="从商店购买物品" tabindex="-1">从商店购买物品 <a class="header-anchor" href="#从商店购买物品" aria-label="Permalink to &quot;从商店购买物品&quot;">​</a></h2><p>当然，如果你想从其他商店购买物品，或者想在自己的商店买买买也是可以的</p><p>首先，你需要左键点击箱子上的牌子，然后会弹出如图的内容，你需要打开聊天栏进行输入：</p><p><img src="'+c+'" alt="在聊天栏打开的商店购买确认"></p><p>然后，根据提示，输入你想要买的物品数量（输入<code>all</code>则为全部购买）</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>注意，是直接输入，和你发聊天消息的时候一样：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>all</span></span></code></pre></div><p>而不是</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/all</span></span></code></pre></div></div><p>如果成功，就会显示如图的提示：</p><p><img src="'+r+'" alt="购买成功提示"></p><h2 id="修改商店属性" tabindex="-1">修改商店属性 <a class="header-anchor" href="#修改商店属性" aria-label="Permalink to &quot;修改商店属性&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>只有商店主人才能进行此操作</p></div><p>想要收购物品？或者觉得商店卖的太贵了？</p><p>没问题，你可以随时进行修改，而不用拆掉在建一个</p><p>首先，右键点击你商店上的牌子，然后会出现如下的信息，你可以直接在聊天栏内点击进行修改：</p><p><img src="'+n+'" alt="商店控制面板"></p>',27)]))}const f=s(d,[["render",h]]);export{v as __pageData,f as default};
